     1→<!DOCTYPE html>
     2→<html lang="en">
     3→<head>
     4→<meta charset="UTF-8">
     5→<meta name="viewport" content="width=device-width, initial-scale=1.0">
     6→<title>Habitat — The fastest path from zero to real</title>
     7→<meta name="description" content="From idea to live product. Habitat evenings, technical hackathons, and founder residencies across Belgium.">
     8→<link rel="preconnect" href="https://fonts.googleapis.com">
     9→<link href="https://fonts.googleapis.com/css2?family=Space+Mono:wght@400;700&family=Outfit:wght@300;400;500;600;700&display=swap" rel="stylesheet">
    10→<style>
    11→/* ============================================
    12→   CSS VARIABLES — Change these to restyle everything
    13→   ============================================ */
    14→:root {
    15→  --black: #0a0a0a;
    16→  --white: #f5f2eb;
    17→  --cream: #ede9df;
    18→  --gray: #8a8780;
    19→  --gray-light: #c4c1b8;
    20→  --accent: #3d5afc;       /* Habitat blue */
    21→  --accent-glow: #5b74ff;
    22→  --coral: #ff6b4a;
    23→  --teal: #1dd4a0;
    24→  --purple: #a374ff;
    25→  --font-display: 'Space Mono', monospace;
    26→  --font-body: 'Outfit', sans-serif;
    27→}
    28→
    29→/* ============================================
    30→   RESET & BASE
    31→   ============================================ */
    32→*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
    33→
    34→html { scroll-behavior: smooth; }
    35→
    36→body {
    37→  font-family: var(--font-body);
    38→  background: var(--black);
    39→  color: var(--white);
    40→  line-height: 1.6;
    41→  overflow-x: hidden;
    42→  -webkit-font-smoothing: antialiased;
    43→}
    44→
    45→a { color: inherit; text-decoration: none; }
    46→img { max-width: 100%; display: block; }
    47→
    48→/* ============================================
    49→   LAYOUT
    50→   ============================================ */
    51→.container {
    52→  max-width: 1200px;
    53→  margin: 0 auto;
    54→  padding: 0 24px;
    55→}
    56→
    57→section {
    58→  padding: 120px 0;
    59→}
    60→
    61→/* ============================================
    62→   NAVIGATION
    63→   ============================================ */
    64→nav {
    65→  position: fixed;
    66→  top: 0;
    67→  left: 0;
    68→  right: 0;
    69→  z-index: 100;
    70→  padding: 20px 0;
    71→  background: rgba(10,10,10,0.85);
    72→  backdrop-filter: blur(20px);
    73→  border-bottom: 1px solid rgba(245,242,235,0.06);
    74→}
    75→
    76→nav .container {
    77→  display: flex;
    78→  align-items: center;
    79→  justify-content: space-between;
    80→}
    81→
    82→.logo {
    83→  font-family: var(--font-display);
    84→  font-size: 18px;
    85→  font-weight: 700;
    86→  letter-spacing: -0.5px;
    87→}
    88→
    89→.logo span { color: var(--accent); }
    90→
    91→.nav-links {
    92→  display: flex;
    93→  gap: 32px;
    94→  align-items: center;
    95→  list-style: none;
    96→}
    97→
    98→.nav-links a {
    99→  font-size: 14px;
   100→  font-weight: 400;
   101→  color: var(--gray);
   102→  transition: color 0.2s;
   103→}
   104→
   105→.nav-links a:hover { color: var(--white); }
   106→
   107→.nav-cta {
   108→  background: var(--accent);
   109→  color: var(--black) !important;
   110→  padding: 10px 24px;
   111→  border-radius: 6px;
   112→  font-weight: 600;
   113→  font-size: 14px;
   114→  transition: background 0.2s;
   115→}
   116→
   117→.nav-cta:hover { background: var(--accent-glow); }
   118→
   119→/* ============================================
   120→   HERO
   121→   ============================================ */
   122→.hero {
   123→  min-height: 100vh;
   124→  display: flex;
   125→  align-items: center;
   126→  padding-top: 100px;
   127→  position: relative;
   128→}
   129→
   130→.hero::before {
   131→  content: '';
   132→  position: absolute;
   133→  top: -200px;
   134→  right: -200px;
   135→  width: 600px;
   136→  height: 600px;
   137→  background: radial-gradient(circle, rgba(61,90,252,0.08) 0%, transparent 70%);
   138→  pointer-events: none;
   139→}
   140→
   141→.hero-content {
   142→  max-width: 800px;
   143→}
   144→
   145→.hero-label {
   146→  font-family: var(--font-display);
   147→  font-size: 13px;
   148→  color: var(--accent);
   149→  letter-spacing: 2px;
   150→  text-transform: uppercase;
   151→  margin-bottom: 24px;
   152→  display: flex;
   153→  align-items: center;
   154→  gap: 12px;
   155→}
   156→
   157→.hero-label::before {
   158→  content: '';
   159→  width: 40px;
   160→  height: 1px;
   161→  background: var(--accent);
   162→}
   163→
   164→.hero h1 {
   165→  font-family: var(--font-body);
   166→  font-size: clamp(48px, 7vw, 80px);
   167→  font-weight: 700;
   168→  line-height: 1.05;
   169→  letter-spacing: -2px;
   170→  margin-bottom: 28px;
   171→}
   172→
   173→.hero h1 em {
   174→  font-style: normal;
   175→  color: var(--accent);
   176→}
   177→
   178→.hero-sub {
   179→  font-size: 20px;
   180→  color: var(--gray-light);
   181→  max-width: 560px;
   182→  line-height: 1.6;
   183→  margin-bottom: 48px;
   184→  font-weight: 300;
   185→}
   186→
   187→.hero-buttons {
   188→  display: flex;
   189→  gap: 16px;
   190→  flex-wrap: wrap;
   191→}
   192→
   193→.btn-primary {
   194→  display: inline-flex;
   195→  align-items: center;
   196→  gap: 8px;
   197→  background: var(--accent);
   198→  color: var(--black);
   199→  padding: 16px 32px;
   200→  border-radius: 8px;
   201→  font-weight: 600;
   202→  font-size: 16px;
   203→  transition: all 0.2s;
   204→  border: none;
   205→  cursor: pointer;
   206→}
   207→
   208→.btn-primary:hover {
   209→  background: var(--accent-glow);
   210→  transform: translateY(-1px);
   211→}
   212→
   213→.btn-secondary {
   214→  display: inline-flex;
   215→  align-items: center;
   216→  gap: 8px;
   217→  background: transparent;
   218→  color: var(--white);
   219→  padding: 16px 32px;
   220→  border-radius: 8px;
   221→  font-weight: 500;
   222→  font-size: 16px;
   223→  border: 1px solid rgba(245,242,235,0.15);
   224→  transition: all 0.2s;
   225→  cursor: pointer;
   226→}
   227→
   228→.btn-secondary:hover {
   229→  border-color: rgba(245,242,235,0.4);
   230→  background: rgba(245,242,235,0.04);
   231→}
   232→
   233→/* ============================================
   234→   STATS TICKER
   235→   ============================================ */
   236→.stats-bar {
   237→  border-top: 1px solid rgba(245,242,235,0.08);
   238→  border-bottom: 1px solid rgba(245,242,235,0.08);
   239→  padding: 40px 0;
   240→}
   241→
   242→.stats-grid {
   243→  display: grid;
   244→  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
   245→  gap: 32px;
   246→  text-align: center;
   247→}
   248→
   249→.stat-num {
   250→  font-family: var(--font-display);
   251→  font-size: 36px;
   252→  font-weight: 700;
   253→  color: var(--white);
   254→  line-height: 1;
   255→}
   256→
   257→.stat-label {
   258→  font-size: 13px;
   259→  color: var(--gray);
   260→  margin-top: 6px;
   261→  font-weight: 400;
   262→}
   263→
   264→/* ============================================
   265→   PHOTO STRIP (scrolling event photos)
   266→   ============================================ */
   267→.photo-strip {
   268→  padding: 80px 0;
   269→  overflow: hidden;
   270→}
   271→
   272→.photo-row {
   273→  display: flex;
   274→  gap: 16px;
   275→  animation: scroll-photos 30s linear infinite;
   276→}
   277→
   278→.photo-row img, .photo-row .photo-placeholder {
   279→  width: 340px;
   280→  height: 220px;
   281→  object-fit: cover;
   282→  border-radius: 12px;
   283→  flex-shrink: 0;
   284→}
   285→
   286→/* === IMAGE PLACEHOLDERS ===
   287→   These gray boxes show where YOUR photos go.
   288→   Replace <div class="photo-placeholder"> with <img src="images/your-photo.jpg">
   289→*/
   290→.photo-placeholder {
   291→  background: rgba(245,242,235,0.06);
   292→  border: 1px dashed rgba(245,242,235,0.15);
   293→  display: flex;
   294→  align-items: center;
   295→  justify-content: center;
   296→  color: var(--gray);
   297→  font-size: 13px;
   298→  font-family: var(--font-display);
   299→}
   300→
   301→@keyframes scroll-photos {
   302→  0% { transform: translateX(0); }
   303→  100% { transform: translateX(calc(-356px * 5)); }
   304→}
   305→
   306→/* ============================================
   307→   THREE PRODUCTS
   308→   ============================================ */
   309→.products { padding: 120px 0; }
   310→
   311→.section-label {
   312→  font-family: var(--font-display);
   313→  font-size: 13px;
   314→  color: var(--accent);
   315→  letter-spacing: 2px;
   316→  text-transform: uppercase;
   317→  margin-bottom: 16px;
   318→}
   319→
   320→.section-title {
   321→  font-size: clamp(36px, 5vw, 56px);
   322→  font-weight: 700;
   323→  letter-spacing: -1.5px;
   324→  margin-bottom: 16px;
   325→  line-height: 1.1;
   326→}
   327→
   328→.section-sub {
   329→  font-size: 18px;
   330→  color: var(--gray-light);
   331→  max-width: 600px;
   332→  margin-bottom: 64px;
   333→  font-weight: 300;
   334→}
   335→
   336→.product-cards {
   337→  display: grid;
   338→  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
   339→  gap: 24px;
   340→}
   341→
   342→.product-card {
   343→  background: rgba(245,242,235,0.03);
   344→  border: 1px solid rgba(245,242,235,0.08);
   345→  border-radius: 16px;
   346→  padding: 40px 32px;
   347→  transition: all 0.3s;
   348→  position: relative;
   349→  overflow: hidden;
   350→}
   351→
   352→.product-card:hover {
   353→  border-color: rgba(245,242,235,0.16);
   354→  transform: translateY(-4px);
   355→}
   356→
   357→.product-card::before {
   358→  content: '';
   359→  position: absolute;
   360→  top: 0;
   361→  left: 0;
   362→  right: 0;
   363→  height: 3px;
   364→}
   365→
   366→.product-card.evenings::before { background: var(--teal); }
   367→.product-card.hackathons::before { background: var(--accent); }
   368→.product-card.residency::before { background: var(--purple); }
   369→
   370→.product-tag {
   371→  display: inline-block;
   372→  font-family: var(--font-display);
   373→  font-size: 11px;
   374→  letter-spacing: 1.5px;
   375→  text-transform: uppercase;
   376→  padding: 6px 14px;
   377→  border-radius: 4px;
   378→  margin-bottom: 24px;
   379→}
   380→
   381→.evenings .product-tag { background: rgba(29,212,160,0.12); color: var(--teal); }
   382→.hackathons .product-tag { background: rgba(61,90,252,0.12); color: var(--accent-glow); }
   383→.residency .product-tag { background: rgba(163,116,255,0.12); color: var(--purple); }
   384→
   385→.product-card h3 {
   386→  font-size: 24px;
   387→  font-weight: 600;
   388→  margin-bottom: 12px;
   389→  letter-spacing: -0.5px;
   390→}
   391→
   392→.product-card p {
   393→  color: var(--gray-light);
   394→  font-size: 15px;
   395→  line-height: 1.7;
   396→  margin-bottom: 24px;
   397→}
   398→
   399→.product-details {
   400→  list-style: none;
   401→  display: flex;
   402→  flex-wrap: wrap;
   403→  gap: 8px;
   404→}
   405→
   406→.product-details li {
   407→  font-size: 13px;
   408→  color: var(--gray);
   409→  background: rgba(245,242,235,0.04);
   410→  padding: 6px 14px;
   411→  border-radius: 20px;
   412→  border: 1px solid rgba(245,242,235,0.06);
   413→}
   414→
   415→/* ============================================
   416→   FUNNEL SECTION
   417→   ============================================ */
   418→.funnel {
   419→  background: rgba(245,242,235,0.02);
   420→  border-top: 1px solid rgba(245,242,235,0.06);
   421→  border-bottom: 1px solid rgba(245,242,235,0.06);
   422→}
   423→
   424→.funnel-visual {
   425→  display: flex;
   426→  align-items: center;
   427→  justify-content: center;
   428→  gap: 24px;
   429→  flex-wrap: wrap;
   430→  padding: 40px 0;
   431→}
   432→
   433→.funnel-step {
   434→  text-align: center;
   435→  flex: 1;
   436→  min-width: 160px;
   437→}
   438→
   439→.funnel-num {
   440→  font-family: var(--font-display);
   441→  font-size: 28px;
   442→  font-weight: 700;
   443→  margin-bottom: 4px;
   444→}
   445→
   446→.funnel-label {
   447→  font-size: 14px;
   448→  color: var(--gray);
   449→}
   450→
   451→.funnel-arrow {
   452→  color: var(--gray);
   453→  font-size: 24px;
   454→  opacity: 0.3;
   455→}
   456→
   457→/* ============================================
   458→   LOGOS
   459→   ============================================ */
   460→.logos-section {
   461→  padding: 80px 0;
   462→  text-align: center;
   463→}
   464→
   465→.logos-label {
   466→  font-size: 13px;
   467→  color: var(--gray);
   468→  text-transform: uppercase;
   469→  letter-spacing: 2px;
   470→  margin-bottom: 40px;
   471→  font-family: var(--font-display);
   472→}
   473→
   474→.logos-row {
   475→  display: flex;
   476→  align-items: center;
   477→  justify-content: center;
   478→  gap: 48px;
   479→  flex-wrap: wrap;
   480→  opacity: 0.5;
   481→}
   482→
   483→/* === LOGO IMAGE PLACEHOLDERS ===
   484→   Replace these with: <img src="images/logos/google.png" alt="Google" height="32">
   485→*/
   486→.logo-placeholder {
   487→  color: var(--gray);
   488→  font-family: var(--font-display);
   489→  font-size: 14px;
   490→  padding: 12px 20px;
   491→  border: 1px dashed rgba(245,242,235,0.15);
   492→  border-radius: 6px;
   493→}
   494→
   495→/* ============================================
   496→   TESTIMONIALS
   497→   ============================================ */
   498→.testimonials {
   499→  padding: 120px 0;
   500→}
   501→
   502→.testimonial-grid {
   503→  display: grid;
   504→  grid-template-columns: repeat(auto-fit, minmax(340px, 1fr));
   505→  gap: 24px;
   506→  margin-top: 64px;
   507→}
   508→
   509→.testimonial-card {
   510→  background: rgba(245,242,235,0.03);
   511→  border: 1px solid rgba(245,242,235,0.08);
   512→  border-radius: 16px;
   513→  padding: 36px;
   514→}
   515→
   516→.testimonial-text {
   517→  font-size: 17px;
   518→  line-height: 1.7;
   519→  margin-bottom: 24px;
   520→  color: var(--cream);
   521→  font-weight: 300;
   522→}
   523→
   524→.testimonial-author {
   525→  display: flex;
   526→  align-items: center;
   527→  gap: 14px;
   528→}
   529→
   530→/* === TESTIMONIAL PHOTO PLACEHOLDER ===
   531→   Replace with: <img src="images/people/leon.jpg" alt="Leon" class="testimonial-avatar">
   532→*/
   533→.testimonial-avatar, .avatar-placeholder {
   534→  width: 44px;
   535→  height: 44px;
   536→  border-radius: 50%;
   537→  object-fit: cover;
   538→}
   539→
   540→.avatar-placeholder {
   541→  background: rgba(245,242,235,0.08);
   542→  border: 1px dashed rgba(245,242,235,0.15);
   543→  display: flex;
   544→  align-items: center;
   545→  justify-content: center;
   546→  font-size: 16px;
   547→}
   548→
   549→.testimonial-name {
   550→  font-weight: 600;
   551→  font-size: 15px;
   552→}
   553→
   554→.testimonial-role {
   555→  font-size: 13px;
   556→  color: var(--gray);
   557→}
   558→
   559→/* ============================================
   560→   WHY SECTION
   561→   ============================================ */
   562→.why-grid {
   563→  display: grid;
   564→  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
   565→  gap: 48px;
   566→  margin-top: 64px;
   567→}
   568→
   569→.why-item h3 {
   570→  font-size: 20px;
   571→  font-weight: 600;
   572→  margin-bottom: 10px;
   573→  letter-spacing: -0.3px;
   574→}
   575→
   576→.why-item p {
   577→  font-size: 15px;
   578→  color: var(--gray-light);
   579→  line-height: 1.7;
   580→}
   581→
   582→.why-item-accent {
   583→  width: 32px;
   584→  height: 3px;
   585→  margin-bottom: 20px;
   586→  border-radius: 2px;
   587→}
   588→
   589→/* ============================================
   590→   CTA SECTION
   591→   ============================================ */
   592→.cta-section {
   593→  padding: 160px 0;
   594→  text-align: center;
   595→  position: relative;
   596→}
   597→
   598→.cta-section::before {
   599→  content: '';
   600→  position: absolute;
   601→  top: 50%;
   602→  left: 50%;
   603→  transform: translate(-50%, -50%);
   604→  width: 500px;
   605→  height: 500px;
   606→  background: radial-gradient(circle, rgba(61,90,252,0.06) 0%, transparent 70%);
   607→  pointer-events: none;
   608→}
   609→
   610→.cta-section h2 {
   611→  font-size: clamp(36px, 5vw, 60px);
   612→  font-weight: 700;
   613→  letter-spacing: -1.5px;
   614→  margin-bottom: 20px;
   615→  line-height: 1.1;
   616→}
   617→
   618→.cta-section p {
   619→  font-size: 18px;
   620→  color: var(--gray-light);
   621→  margin-bottom: 40px;
   622→  font-weight: 300;
   623→}
   624→
   625→/* ============================================
   626→   FOOTER
   627→   ============================================ */
   628→footer {
   629→  border-top: 1px solid rgba(245,242,235,0.06);
   630→  padding: 60px 0 40px;
   631→}
   632→
   633→.footer-grid {
   634→  display: grid;
   635→  grid-template-columns: 2fr 1fr 1fr 1fr;
   636→  gap: 48px;
   637→  margin-bottom: 60px;
   638→}
   639→
   640→.footer-brand p {
   641→  color: var(--gray);
   642→  font-size: 14px;
   643→  margin-top: 12px;
   644→  max-width: 280px;
   645→  line-height: 1.6;
   646→}
   647→
   648→.footer-col h4 {
   649→  font-size: 13px;
   650→  text-transform: uppercase;
   651→  letter-spacing: 1.5px;
   652→  color: var(--gray);
   653→  margin-bottom: 16px;
   654→  font-family: var(--font-display);
   655→}
   656→
   657→.footer-col a {
   658→  display: block;
   659→  font-size: 14px;
   660→  color: var(--gray-light);
   661→  padding: 4px 0;
   662→  transition: color 0.2s;
   663→}
   664→
   665→.footer-col a:hover { color: var(--white); }
   666→
   667→.footer-bottom {
   668→  border-top: 1px solid rgba(245,242,235,0.06);
   669→  padding-top: 24px;
   670→  display: flex;
   671→  justify-content: space-between;
   672→  align-items: center;
   673→  color: var(--gray);
   674→  font-size: 13px;
   675→}
   676→
   677→/* ============================================
   678→   RESPONSIVE
   679→   ============================================ */
   680→@media (max-width: 768px) {
   681→  section { padding: 80px 0; }
   682→  .hero { min-height: auto; padding-top: 120px; padding-bottom: 60px; }
   683→  .hero h1 { font-size: 40px; letter-spacing: -1px; }
   684→  .stats-grid { grid-template-columns: repeat(3, 1fr); gap: 24px; }
   685→  .footer-grid { grid-template-columns: 1fr 1fr; }
   686→  .nav-links { display: none; }
   687→  .funnel-arrow { display: none; }
   688→  .funnel-visual { gap: 16px; }
   689→  .testimonial-grid { grid-template-columns: 1fr; }
   690→  .product-cards { grid-template-columns: 1fr; }
   691→}
   692→
   693→/* ============================================
   694→   ANIMATIONS (on scroll)
   695→   ============================================ */
   696→.fade-up {
   697→  opacity: 0;
